from pydantic import BaseModel, validator

class LLMActionResponse(BaseModel):
    action: str
    target_file: str

    @validator('action')
    def action_must_be_allowed(cls, v):
        if v not in {'read', 'append'}:
            raise ValueError(f'Disallowed action: {v}')
        return v

    @validator('target_file')
    def no_traversal(cls, v):
        if '..' in v:
            raise ValueError('Directory traversal detected')
        return v

