ALLOWED_TOOLS = {"search_knowledge_base", "get_weather", "summarise_text"}

def execute_tool_call(tool_name: str, args: dict) -> dict:
    if tool_name not in ALLOWED_TOOLS:
        raise PermissionError(
            f"Tool '{tool_name}' is not on the allow-list. "
            f"Permitted tools: {sorted(ALLOWED_TOOLS)}"
        )
    return TOOL_REGISTRY[tool_name](**args)

